import{c as a,Q as s,j as r,m as t}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Search with seeds","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/search-with-seeds.md","filePath":"user-guide/search-with-seeds.md","lastUpdated":null}'),i={name:"user-guide/search-with-seeds.md"};function d(o,e,n,c,h,l){return s(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="search-with-seeds" tabindex="-1">Search with seeds <a class="header-anchor" href="#search-with-seeds" aria-label="Permalink to &quot;Search with seeds&quot;">​</a></h1><p>Audience: DJs and UI users<br> Goal: find related tracks from selected seed tracks<br> Type: how-to</p><p>Seed search starts from one or more selected tracks and asks the app for related candidates. The result is a review list, not a final musical verdict.</p><h2 id="select-seeds" tabindex="-1">Select seeds <a class="header-anchor" href="#select-seeds" aria-label="Permalink to &quot;Select seeds&quot;">​</a></h2><p>In the library or result rows, use the seed action. Keep seeds focused:</p><ul><li>one track is enough for a narrow search;</li><li>several tracks can describe a crate or a small set direction;</li><li>avoid mixing unrelated ideas unless you want broad discovery.</li></ul><h2 id="sonara-search" tabindex="-1">SONARA search <a class="header-anchor" href="#sonara-search" aria-label="Permalink to &quot;SONARA search&quot;">​</a></h2><p>Use SONARA when you want feature-based matching: energy, rhythm, loudness, timbre, harmonic descriptors, and tempo-related features.</p><p>The SONARA tab supports modes such as balanced, vibe, sound, DJ transition, and custom mixer settings. It requires stored SONARA features.</p><h2 id="mert-search" tabindex="-1">MERT search <a class="header-anchor" href="#mert-search" aria-label="Permalink to &quot;MERT search&quot;">​</a></h2><p>Use MERT when you want audio embedding similarity from seed tracks. It requires stored MERT embeddings.</p><h2 id="review-results" tabindex="-1">Review results <a class="header-anchor" href="#review-results" aria-label="Permalink to &quot;Review results&quot;">​</a></h2><p>Each result row shows a score and reason/breakdown hints when available. Treat the score as a ranking aid. Preview the track, inspect metadata, then add only useful candidates to the current set.</p>',13)])])}const p=a(i,[["render",d]]);export{m as __pageData,p as default};
